using Microsoft.EntityFrameworkCore;using System.Data;using verii_metivon_api.Core.Auth;using verii_metivon_api.Core.Paging;using verii_metivon_api.Core.Persistence;using verii_metivon_api.Modules.GeneralSettings;using verii_metivon_api.Modules.Inventory.Domain.Entities;using verii_metivon_api.Modules.LandedCosts.Domain.Entities;using verii_metivon_api.Modules.Products.Domain.Entities;using verii_metivon_api.Modules.TradeOperations.Domain.Entities;
namespace verii_metivon_api.Modules.LandedCosts.Application.Services;
public sealed class ImportDossierQuery:PagedQuery{public ImportDossierStatus?Status{get;init;}public long?SupplierId{get;init;}public long?BranchId{get;init;}}
public sealed record ImportDossierRow(long Id,string DossierNumber,string Supplier,string CurrencyCode,string IncotermCode,DateOnly OpenDate,DateOnly? ReceiptDate,DateTime MatchedAt,string? GoodsReceiptNumber,int ReceiptCount,string Status,int LineCount,decimal GoodsAmount,decimal GoodsAmountLocal,decimal LandedCostAmount,decimal FinalAmount);
public sealed record CreateImportLineRequest(long?PurchaseOrderLineId,long?GoodsReceiptLineId,long ProductId,decimal Quantity,decimal?NetWeight,decimal?GrossWeight,decimal?Volume,decimal ForeignUnitPrice,decimal?TransactionExchangeRate,decimal?CustomsExchangeRate,decimal?CostingExchangeRate,long?ReceiptTransactionId);
public sealed record CreateImportDossierRequest(long? TradeDossierId,string DossierNumber,long BranchId,long SupplierId,long CurrencyId,string IncotermCode,DateOnly OpenDate,DateOnly?EstimatedArrivalDate,decimal TransactionExchangeRate,decimal CustomsExchangeRate,decimal CostingExchangeRate,string?Notes,IReadOnlyList<CreateImportLineRequest>Lines);
public sealed record AddDossierCostRequest(long LandedCostTypeId,LandedCostAmountType AmountType,LandedCostAllocationMethod?AllocationMethod,LandedCostSourceType SourceType,long?SupplierId,string?InvoiceNumber,DateOnly?InvoiceDate,string?PaymentReference,DateOnly?PaymentDate,long CurrencyId,decimal ForeignAmount,decimal OriginalExchangeRate,decimal ExchangeRate,DateOnly?ExchangeRateDate,string?ExchangeRateSource,string?Description,IReadOnlyDictionary<long,decimal>?ManualAllocations);
public sealed record SaveLandedCostTypeRequest(string Code,string Name,string?Description,LandedCostAllocationMethod DefaultAllocationMethod,bool IncludeInCustomsValue,bool CapitalizeToInventory,long?ClearingAccountId,long?VarianceAccountId,bool IsActive,bool IsDefault,int DisplayOrder);
public sealed record FinalizeDossierRequest(DateOnly PostingDate,long?FiscalPeriodId,long?InventoryAccountId,long?ConsumedVarianceAccountId,long?ClearingAccountId);
public interface ILandedCostService{Task<ApiResponse<PagedResult<ImportDossierRow>>>GetPagedAsync(ImportDossierQuery q,CancellationToken ct);Task<ApiResponse<object>>CreateAsync(CreateImportDossierRequest r,CancellationToken ct);Task<ApiResponse<object>>AddCostAsync(long id,AddDossierCostRequest r,CancellationToken ct);Task<ApiResponse<object>>AddTradeDossierCostAsync(long tradeDossierId,AddDossierCostRequest r,CancellationToken ct);Task<ApiResponse<object>>AllocateAsync(long id,CancellationToken ct);Task<ApiResponse<object>>AllocateTradeDossierAsync(long tradeDossierId,CancellationToken ct);Task<ApiResponse<object>>FinalizeAsync(long id,FinalizeDossierRequest r,CancellationToken ct);Task<ApiResponse<object>>FinalizeTradeDossierAsync(long tradeDossierId,FinalizeDossierRequest r,CancellationToken ct);Task<ApiResponse<object>>SaveTypeAsync(SaveLandedCostTypeRequest r,CancellationToken ct);}
public sealed class LandedCostService(MetivonDbContext db):ILandedCostService{
 public async Task<ApiResponse<PagedResult<ImportDossierRow>>>GetPagedAsync(ImportDossierQuery q,CancellationToken ct){var x=db.ImportDossiers.Include(v=>v.Supplier).Include(v=>v.Lines).Include(v=>v.Costs).Where(v=>v.TradeDossierId.HasValue&&db.GoodsReceipts.Any(r=>r.TradeDossierId==v.TradeDossierId)).AsQueryable();if(q.Status.HasValue)x=x.Where(v=>v.Status==q.Status);if(q.SupplierId.HasValue)x=x.Where(v=>v.SupplierId==q.SupplierId);if(q.BranchId.HasValue)x=x.Where(v=>v.BranchId==q.BranchId);if(!string.IsNullOrWhiteSpace(q.Search)){var s=q.Search.Trim();x=x.Where(v=>v.DossierNumber.Contains(s)||v.Supplier.Name.Contains(s)||(v.CustomsDeclarationNumber!=null&&v.CustomsDeclarationNumber.Contains(s))||db.GoodsReceipts.Any(r=>r.TradeDossierId==v.TradeDossierId&&r.ReceiptNumber.Contains(s)));}x=x.ApplyPagedFilters(q);var total=await x.CountAsync(ct);var rows=await x.OrderByDescending(v=>v.OpenDate).ThenByDescending(v=>v.Id).Skip((q.NormalizedPageNumber-1)*q.NormalizedPageSize).Take(q.NormalizedPageSize).Select(v=>new ImportDossierRow(v.Id,v.DossierNumber,v.Supplier.Name,v.CurrencyCode,v.IncotermCode,v.OpenDate,db.GoodsReceipts.Where(r=>r.TradeDossierId==v.TradeDossierId).Max(r=>(DateOnly?)r.ReceiptDate),v.CreatedAt,db.GoodsReceipts.Where(r=>r.TradeDossierId==v.TradeDossierId).OrderByDescending(r=>r.ReceiptDate).ThenByDescending(r=>r.Id).Select(r=>r.ReceiptNumber).FirstOrDefault(),db.GoodsReceipts.Count(r=>r.TradeDossierId==v.TradeDossierId),v.Status.ToString(),v.Lines.Count,v.Lines.Sum(l=>l.ForeignGoodsAmount),v.Lines.Sum(l=>l.GoodsAmountLocal),v.Costs.Sum(c=>c.LocalAmount),v.Lines.Sum(l=>l.GoodsAmountLocal+l.AllocatedCostLocal))).ToListAsync(ct);return ApiResponse<PagedResult<ImportDossierRow>>.Ok(new(rows,q.NormalizedPageNumber,q.NormalizedPageSize,total));}
 public async Task<ApiResponse<object>>CreateAsync(CreateImportDossierRequest r,CancellationToken ct){if(r.Lines.Count==0||r.TransactionExchangeRate<=0||r.CustomsExchangeRate<=0||r.CostingExchangeRate<=0)return ApiResponse<object>.Error("Lines and positive exchange rates are required.",400);var currency=await db.Currencies.AsNoTracking().FirstOrDefaultAsync(x=>x.Id==r.CurrencyId&&x.IsActive,ct);if(currency is null)return ApiResponse<object>.Error("An active defined currency is required.",400);var number=r.DossierNumber.Trim().ToUpperInvariant();if(await db.ImportDossiers.AnyAsync(x=>x.DossierNumber==number,ct))return ApiResponse<object>.Error("Dossier number already exists.",409);if(r.TradeDossierId.HasValue){var trade=await db.TradeDossiers.AsNoTracking().FirstOrDefaultAsync(x=>x.Id==r.TradeDossierId.Value,ct);if(trade is null||trade.Direction!=verii_metivon_api.Modules.TradeOperations.Domain.Entities.TradeDirection.Import)return ApiResponse<object>.Error("A valid import trade dossier is required.",400);if(trade.BranchId!=r.BranchId||trade.BusinessPartnerId!=r.SupplierId)return ApiResponse<object>.Error("Trade dossier branch and supplier must match the landed-cost dossier.",409);if(await db.ImportDossiers.AnyAsync(x=>x.TradeDossierId==r.TradeDossierId,ct))return ApiResponse<object>.Error("Trade dossier is already linked to a landed-cost dossier.",409);}var products=await db.Products.Where(x=>r.Lines.Select(l=>l.ProductId).Contains(x.Id)).ToDictionaryAsync(x=>x.Id,ct);var d=new ImportDossier{TradeDossierId=r.TradeDossierId,DossierNumber=number,BranchId=r.BranchId,SupplierId=r.SupplierId,CurrencyId=currency.Id,CurrencyCode=currency.IsoCode,IncotermCode=r.IncotermCode.ToUpperInvariant(),OpenDate=r.OpenDate,EstimatedArrivalDate=r.EstimatedArrivalDate,TransactionExchangeRate=r.TransactionExchangeRate,CustomsExchangeRate=r.CustomsExchangeRate,CostingExchangeRate=r.CostingExchangeRate,Notes=r.Notes};var n=0;foreach(var l in r.Lines){if(l.Quantity<=0||l.ForeignUnitPrice<0||!products.TryGetValue(l.ProductId,out var p))return ApiResponse<object>.Error("Each line requires a valid product, quantity and price.",400);var costingRate=l.CostingExchangeRate??r.CostingExchangeRate;d.Lines.Add(new ImportDossierLine{LineNumber=++n,PurchaseOrderLineId=l.PurchaseOrderLineId,GoodsReceiptLineId=l.GoodsReceiptLineId,ProductId=l.ProductId,Quantity=l.Quantity,NetWeight=l.NetWeight??(p.NetWeight??0)*l.Quantity,GrossWeight=l.GrossWeight??(p.GrossWeight??p.NetWeight??0)*l.Quantity,Volume=l.Volume??(p.Volume??0)*l.Quantity,ForeignUnitPrice=l.ForeignUnitPrice,ForeignGoodsAmount=l.Quantity*l.ForeignUnitPrice,TransactionExchangeRate=l.TransactionExchangeRate??r.TransactionExchangeRate,CustomsExchangeRate=l.CustomsExchangeRate??r.CustomsExchangeRate,CostingExchangeRate=costingRate,GoodsAmountLocal=l.Quantity*l.ForeignUnitPrice*costingRate,ReceiptTransactionId=l.ReceiptTransactionId});}db.ImportDossiers.Add(d);await db.SaveChangesAsync(ct);if(r.TradeDossierId.HasValue){db.TradeDocumentLinks.Add(new(){TradeDossierId=r.TradeDossierId.Value,LinkType=verii_metivon_api.Modules.TradeOperations.Domain.Entities.TradeLinkType.ImportDossier,SourceId=d.Id,ReferenceNumber=d.DossierNumber});await db.SaveChangesAsync(ct);}return ApiResponse<object>.Ok(new{d.Id,d.DossierNumber,d.TradeDossierId,d.CurrencyId,d.CurrencyCode});}
 public async Task<ApiResponse<object>>AddCostAsync(long id,AddDossierCostRequest r,CancellationToken ct){await using var tx=await db.Database.BeginTransactionAsync(ct);var d=await db.ImportDossiers.FirstOrDefaultAsync(x=>x.Id==id,ct);if(d is null)return ApiResponse<object>.Error("Dossier not found.",404);if(d.Status is ImportDossierStatus.Closed or ImportDossierStatus.Cancelled)return ApiResponse<object>.Error("Closed or cancelled dossier cannot be changed.",409);var reopensFinalized=d.Status==ImportDossierStatus.Finalized;if(reopensFinalized&&r.AmountType!=LandedCostAmountType.Adjustment)return ApiResponse<object>.Error("A finalized dossier only accepts an adjustment cost.",409);var type=await db.LandedCostTypes.FirstOrDefaultAsync(x=>x.Id==r.LandedCostTypeId&&x.IsActive,ct);if(type is null)return ApiResponse<object>.Error("Cost type not found.",404);var currency=await db.Currencies.AsNoTracking().FirstOrDefaultAsync(x=>x.Id==r.CurrencyId&&x.IsActive,ct);if(currency is null)return ApiResponse<object>.Error("An active defined currency is required.",400);var baseCurrencyId=await db.Set<GeneralSetting>().AsNoTracking().Where(x=>x.ScopeKey=="GLOBAL").Select(x=>(long?)x.DefaultCurrencyId).FirstOrDefaultAsync(ct);var isBaseCurrency=currency.Id==(baseCurrencyId??(currency.IsDefault?currency.Id:0));var originalRate=isBaseCurrency?1:r.OriginalExchangeRate;var appliedRate=isBaseCurrency?1:r.ExchangeRate;var rateSource=isBaseCurrency?"BaseCurrency":r.ExchangeRateSource?.Trim();if(r.ForeignAmount==0||originalRate<=0||appliedRate<=0)return ApiResponse<object>.Error("Amount, original rate and applied rate are required.",400);if(!isBaseCurrency&&(r.ExchangeRateDate is null||string.IsNullOrWhiteSpace(rateSource)))return ApiResponse<object>.Error("Rate date and source are required for foreign currencies.",400);if(r.SourceType==LandedCostSourceType.PurchaseInvoice&&string.IsNullOrWhiteSpace(r.InvoiceNumber))return ApiResponse<object>.Error("Invoice number is required for invoice sourced costs.",400);if(r.SourceType!=LandedCostSourceType.PurchaseInvoice&&string.IsNullOrWhiteSpace(r.PaymentReference))return ApiResponse<object>.Error("Payment or receipt reference is required.",400);var c=new ImportDossierCost{ImportDossierId=id,LandedCostTypeId=r.LandedCostTypeId,AmountType=r.AmountType,AllocationMethod=r.AllocationMethod??type.DefaultAllocationMethod,SourceType=r.SourceType,SupplierId=r.SupplierId,InvoiceNumber=r.InvoiceNumber,InvoiceDate=r.InvoiceDate,PaymentReference=r.PaymentReference,PaymentDate=r.PaymentDate,CurrencyId=currency.Id,CurrencyCode=currency.IsoCode,ForeignAmount=r.ForeignAmount,OriginalExchangeRate=originalRate,ExchangeRate=appliedRate,ExchangeRateDate=r.ExchangeRateDate,ExchangeRateSource=rateSource,LocalAmount=r.ForeignAmount*appliedRate,Description=r.Description};db.ImportDossierCosts.Add(c);await db.SaveChangesAsync(ct);if(c.AllocationMethod==LandedCostAllocationMethod.Manual&&r.ManualAllocations is not null){if(Math.Abs(r.ManualAllocations.Values.Sum()-c.LocalAmount)>0.01m)return ApiResponse<object>.Error("Manual allocation must equal cost amount.",400);foreach(var a in r.ManualAllocations)db.ImportDossierAllocations.Add(new(){ImportDossierCostId=c.Id,ImportDossierLineId=a.Key,Revision=d.AllocationRevision+1,BasisValue=a.Value,AllocationRate=c.LocalAmount==0?0:a.Value/c.LocalAmount,AllocatedAmount=a.Value,IsManual=true});await db.SaveChangesAsync(ct);}if(reopensFinalized)d.FinalizedAt=null;d.Status=ImportDossierStatus.ReadyForAllocation;await db.SaveChangesAsync(ct);await tx.CommitAsync(ct);return ApiResponse<object>.Ok(new{c.Id,c.CurrencyId,c.CurrencyCode,c.OriginalExchangeRate,AppliedExchangeRate=c.ExchangeRate,c.ExchangeRateDate,c.ExchangeRateSource,c.LocalAmount,c.SourceType});}
 public async Task<ApiResponse<object>>AddTradeDossierCostAsync(long tradeDossierId,AddDossierCostRequest r,CancellationToken ct){var id=await EnsureTradeCostProfileAsync(tradeDossierId,ct);if(!id.Success)return ApiResponse<object>.Error(id.Message,id.StatusCode);return await AddCostAsync(id.Data, r, ct);}
 public async Task<ApiResponse<object>>AllocateAsync(long id,CancellationToken ct){await using var tx=await db.Database.BeginTransactionAsync(ct);var d=await db.ImportDossiers.Include(x=>x.Lines).Include(x=>x.Costs).ThenInclude(x=>x.Allocations).FirstOrDefaultAsync(x=>x.Id==id,ct);if(d is null)return ApiResponse<object>.Error("Dossier not found.",404);if(d.Status>=ImportDossierStatus.Finalized)return ApiResponse<object>.Error("Finalized dossier cannot be recalculated.",409);if(d.Lines.Count==0||d.Costs.Count==0)return ApiResponse<object>.Error("Lines and costs are required.",400);var revision=++d.AllocationRevision;foreach(var line in d.Lines)line.AllocatedCostLocal=0;foreach(var cost in d.Costs){if(cost.AllocationMethod==LandedCostAllocationMethod.Manual){var manual=cost.Allocations.Where(x=>x.IsManual).ToList();if(Math.Abs(manual.Sum(x=>x.AllocatedAmount)-cost.LocalAmount)>0.01m)return ApiResponse<object>.Error("Manual allocation is incomplete.",409);foreach(var a in manual){var line=d.Lines.Single(x=>x.Id==a.ImportDossierLineId);line.AllocatedCostLocal+=a.AllocatedAmount;}continue;}var bases=d.Lines.Select(l=>(line:l,basis:Basis(l,cost.AllocationMethod))).ToList();var totalBasis=bases.Sum(x=>x.basis);if(totalBasis<=0)return ApiResponse<object>.Error($"Allocation basis is zero for {cost.AllocationMethod}.",409);var remaining=cost.LocalAmount;for(var i=0;i<bases.Count;i++){var amount=i==bases.Count-1?remaining:Math.Round(cost.LocalAmount*bases[i].basis/totalBasis,2,MidpointRounding.AwayFromZero);remaining-=amount;var a=new ImportDossierAllocation{ImportDossierCostId=cost.Id,ImportDossierLineId=bases[i].line.Id,Revision=revision,BasisValue=bases[i].basis,AllocationRate=bases[i].basis/totalBasis,AllocatedAmount=amount};db.ImportDossierAllocations.Add(a);bases[i].line.AllocatedCostLocal+=amount;}}foreach(var line in d.Lines)line.FinalUnitCostLocal=(line.GoodsAmountLocal+line.AllocatedCostLocal)/line.Quantity;d.Status=ImportDossierStatus.Allocated;await db.SaveChangesAsync(ct);await tx.CommitAsync(ct);return ApiResponse<object>.Ok(new{d.Id,Revision=revision,TotalGoods=d.Lines.Sum(x=>x.GoodsAmountLocal),TotalCosts=d.Costs.Sum(x=>x.LocalAmount),FinalValue=d.Lines.Sum(x=>x.GoodsAmountLocal+x.AllocatedCostLocal)});}
 public async Task<ApiResponse<object>>AllocateTradeDossierAsync(long tradeDossierId,CancellationToken ct){var id=await EnsureTradeCostProfileAsync(tradeDossierId,ct);if(!id.Success)return ApiResponse<object>.Error(id.Message,id.StatusCode);return await AllocateAsync(id.Data,ct);}
 public async Task<ApiResponse<object>>FinalizeAsync(long id,FinalizeDossierRequest r,CancellationToken ct){await using var tx=await db.Database.BeginTransactionAsync(ct);var d=await db.ImportDossiers.Include(x=>x.Lines).FirstOrDefaultAsync(x=>x.Id==id,ct);if(d is null)return ApiResponse<object>.Error("Dossier not found.",404);if(d.Status!=ImportDossierStatus.Allocated)return ApiResponse<object>.Error("Dossier must be allocated before finalization.",409);decimal inventoryAdjustment=0,consumedAdjustment=0;foreach(var line in d.Lines){if(!line.ReceiptTransactionId.HasValue)continue;var receipt=await db.InventoryTransactions.FirstOrDefaultAsync(x=>x.Id==line.ReceiptTransactionId,ct);if(receipt is null)return ApiResponse<object>.Error($"Receipt transaction missing for line {line.LineNumber}.",409);var old=receipt.UnitCost;var delta=line.FinalUnitCostLocal-old;receipt.UnitCost=line.FinalUnitCostLocal;receipt.TotalCost=receipt.BaseQuantity*receipt.UnitCost;var layer=await db.InventoryCostLayers.FirstOrDefaultAsync(x=>x.ReceiptTransactionId==receipt.Id,ct);if(layer is not null){inventoryAdjustment+=layer.RemainingQuantity*delta;consumedAdjustment+=(layer.OriginalQuantity-layer.RemainingQuantity)*delta;layer.UnitCost=line.FinalUnitCostLocal;}var balance=await db.InventoryBalances.FirstOrDefaultAsync(x=>x.ProductId==receipt.ProductId&&x.WarehouseId==receipt.WarehouseId&&x.StorageLocationId==receipt.StorageLocationId&&x.InventoryStatusId==receipt.InventoryStatusId&&x.InventoryLotId==receipt.InventoryLotId&&x.InventorySerialId==receipt.InventorySerialId,ct);if(balance is not null)balance.InventoryValue+=Math.Min(balance.PhysicalQuantity,line.Quantity)*delta;}d.Status=ImportDossierStatus.Finalized;d.FinalizedAt=DateTime.UtcNow;await db.SaveChangesAsync(ct);await tx.CommitAsync(ct);return ApiResponse<object>.Ok(new{d.Id,InventoryAdjustment=inventoryAdjustment,ConsumedAdjustment=consumedAdjustment,TotalAdjustment=inventoryAdjustment+consumedAdjustment});}
 public async Task<ApiResponse<object>>FinalizeTradeDossierAsync(long tradeDossierId,FinalizeDossierRequest r,CancellationToken ct){var id=await EnsureTradeCostProfileAsync(tradeDossierId,ct);if(!id.Success)return ApiResponse<object>.Error(id.Message,id.StatusCode);return await FinalizeAsync(id.Data,r,ct);}
 public async Task<ApiResponse<object>>SaveTypeAsync(SaveLandedCostTypeRequest r,CancellationToken ct){var code=r.Code.Trim().ToUpperInvariant();if(await db.LandedCostTypes.AnyAsync(x=>x.Code==code,ct))return ApiResponse<object>.Error("Cost type code exists.",409);var e=new LandedCostType{Code=code,Name=r.Name.Trim(),Description=r.Description,DefaultAllocationMethod=r.DefaultAllocationMethod,IncludeInCustomsValue=r.IncludeInCustomsValue,CapitalizeToInventory=r.CapitalizeToInventory,ClearingAccountId=r.ClearingAccountId,VarianceAccountId=r.VarianceAccountId,IsActive=r.IsActive,IsDefault=r.IsDefault,DisplayOrder=r.DisplayOrder};db.LandedCostTypes.Add(e);await db.SaveChangesAsync(ct);return ApiResponse<object>.Ok(new{e.Id});}
 private async Task<ApiResponse<long>>EnsureTradeCostProfileAsync(long tradeDossierId,CancellationToken ct){await using var tx=await db.Database.BeginTransactionAsync(IsolationLevel.Serializable,ct);var trade=await db.TradeDossiers.AsNoTracking().FirstOrDefaultAsync(x=>x.Id==tradeDossierId,ct);if(trade is null)return ApiResponse<long>.Error("Trade dossier not found.",404);if(trade.Direction!=TradeDirection.Import)return ApiResponse<long>.Error("Costs can only be added to an import dossier.",409);if(trade.Status is TradeDossierStatus.Closed or TradeDossierStatus.Cancelled)return ApiResponse<long>.Error("Closed or cancelled trade dossier cannot be changed.",409);var existing=await db.ImportDossiers.Where(x=>x.TradeDossierId==tradeDossierId).Select(x=>(long?)x.Id).FirstOrDefaultAsync(ct);if(existing.HasValue){await tx.CommitAsync(ct);return ApiResponse<long>.Ok(existing.Value);}var dossier=new ImportDossier{TradeDossierId=trade.Id,DossierNumber=trade.DossierNumber,Status=ImportDossierStatus.Draft,BranchId=trade.BranchId,SupplierId=trade.BusinessPartnerId,CurrencyId=trade.CurrencyId,CurrencyCode=trade.CurrencyCode,IncotermCode=trade.IncotermCode,OpenDate=trade.OpenDate,EstimatedArrivalDate=trade.EstimatedArrivalDate,ActualArrivalDate=trade.ActualArrivalDate,TransactionExchangeRate=1,CustomsExchangeRate=1,CostingExchangeRate=1,Notes="Dış ticaret dosyasının otomatik maliyet profili."};db.ImportDossiers.Add(dossier);await db.SaveChangesAsync(ct);await tx.CommitAsync(ct);return ApiResponse<long>.Ok(dossier.Id);}
 private static decimal Basis(ImportDossierLine l,LandedCostAllocationMethod m)=>m switch{LandedCostAllocationMethod.Amount=>l.GoodsAmountLocal,LandedCostAllocationMethod.Quantity=>l.Quantity,LandedCostAllocationMethod.Weight=>l.GrossWeight,LandedCostAllocationMethod.Volume=>l.Volume,LandedCostAllocationMethod.Equal=>1,_=>0};}
